            var options = new VectorSearchOptions<MovieWithPlot>()
            {
                Filter = Builders<MovieWithPlot>.Filter.Eq(m => m.Plot.Rating, 5)
                         & Builders<MovieWithPlot>.Filter.Gt("year", 1900),
                IndexName = nestedVectorIndexName,
                ReturnStoredSource = true,
                EmbeddedScoreMode = SearchScoreFunction.Average
            };

            var results = nestedVectorCollection
                .Aggregate()
                .VectorSearch(m => m.Plot.PlotEmbedding, vector, 1, options)
                .Project<MovieWithPlot>(Builders<MovieWithPlot>.Projection
                    .Include(m => m.Title)
                    .MetaVectorSearchScore(p => p.Score))
                .ToList();

            results.Count.Should().Be(1);
            results[0].Title.Should().Be("The Charge of the Light Brigade");
            results.Should().OnlyContain(m => m.Score > 0.9);
        }

        private IMongoCollection<EmbeddedMovie> GetEmbeddedMoviesCollection() => _mongoClient
            .GetDatabase("sample_mflix")
            .GetCollection<EmbeddedMovie>("embedded_movies");

        [BsonIgnoreExtraElements]
        public class EmbeddedMovie
        {
            [BsonElement("title")]
            public string Title { get; set; }

            [BsonElement("plot_embedding")]
            public double[] Embedding { get; set; }

            [BsonElement("score")]
            public double Score { get; set; }
        }

        [BsonIgnoreExtraElements]
        public class BinaryVectorSearchItem
        {
            [BsonElement("int8Vector")]
            public BinaryVectorInt8 VectorInt8 { get; set; }

            [BsonElement("float32Vector")]
            public BinaryVectorFloat32 VectorFloat32 { get; set; }

            [BsonElement("year")]
            public double Year { get; set; }

            [BsonElement("vectorSearchScore")]
            public double Score { get; set; }
        }

        [BsonIgnoreExtraElements]
        public class MovieWithPlot
        {
            [BsonElement("title")]
            public string Title { get; set; }

            [BsonElement("year")]
            public int Year { get; set; }

            [BsonElement("available")]
            public bool Available { get; set; }

            [BsonElement("score")]
            public double Score { get; set; }

            [BsonElement("plot")]
            public NestedPlot Plot { get; set; }
        }

        public class NestedPlot
        {
            [BsonElement("plot")]
            public string Plot { get; set; }

            [BsonElement("rating")]
            public int Rating  { get; set; }

            [BsonElement("plot-embedding")]
            public float[] PlotEmbedding  { get; set; }
        }

        private static string GetRandomName() => $"test_{Guid.NewGuid():N}";

        private bool TryGetIndex<TDocument>(
            IMongoCollection<TDocument> collection, string indexName, out BsonDocument indexDefinition)
        {
            indexDefinition = collection.SearchIndexes.List().ToList()
                .SingleOrDefault(i => i["name"].AsString == indexName)?.AsBsonDocument;

            return indexDefinition != null;
        }

        private void SkipTests() => throw new SkipException("Test skipped because of CSHARP-5840; Atlas does not currently support these features.");
    }
